const MONTHS_CALENDAR = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const MONTHS_RAINFALL_YEAR = ["Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct"];

const COLOURS = {
  current: "#1565C0",
  high: "#2E7D32",
  low: "#C62828",
  median: "#222222",
  other: "rgba(138,138,138,0.18)"
};

function buildHistoricalRainfallYears() {
  const byYear = new Map();
  HISTORICAL_MONTHLY.forEach(row => byYear.set(Number(row.Year), row));

  const records = [];

  [...byYear.keys()].sort((a, b) => a - b).forEach(year => {
    const prev = byYear.get(year - 1);
    const curr = byYear.get(year);
    if (!prev || !curr) return;

    const vals = [
      Number(prev.Nov), Number(prev.Dec),
      Number(curr.Jan), Number(curr.Feb), Number(curr.Mar), Number(curr.Apr),
      Number(curr.May), Number(curr.Jun), Number(curr.Jul), Number(curr.Aug),
      Number(curr.Sep), Number(curr.Oct)
    ];

    if (vals.some(v => !Number.isFinite(v))) return;

    let cumulative = 0;
    const points = vals.map((v, i) => {
      cumulative += v;
      return { x: i, y: round1(cumulative) };
    });

    records.push({
      yearEndingOctober: year,
      total: round1(cumulative),
      points
    });
  });

  return records;
}

function round1(x) {
  return Math.round((Number(x) + Number.EPSILON) * 10) / 10;
}

function median(values) {
  const v = values.filter(Number.isFinite).slice().sort((a, b) => a - b);
  if (!v.length) return NaN;
  const mid = Math.floor(v.length / 2);
  return v.length % 2 ? v[mid] : (v[mid - 1] + v[mid]) / 2;
}

function buildMedianSeries(records) {
  return MONTHS_RAINFALL_YEAR.map((_, i) => ({
    x: i,
    y: round1(median(records.map(r => r.points[i].y)))
  }));
}

function latestDailyPoint(daily) {
  return daily[daily.length - 1];
}

function buildDatasets(records, currentDaily) {
  const sortedHigh = records.slice().sort((a, b) => b.total - a.total);
  const sortedLow = records.slice().sort((a, b) => a.total - b.total);
  const top3 = sortedHigh.slice(0, 3);
  const bottom3 = sortedLow.slice(0, 3);
  const highlightYears = new Set([...top3, ...bottom3].map(r => r.yearEndingOctober));

  const datasets = [];

  records.forEach(r => {
    if (highlightYears.has(r.yearEndingOctober)) return;
    datasets.push({
      label: "Other rainfall years",
      data: r.points,
      borderColor: COLOURS.other,
      borderWidth: 1,
      pointRadius: 0,
      tension: 0,
      order: 20
    });
  });

  const widths = [3.8, 2.8, 2.0];
  top3.forEach((r, idx) => {
    datasets.push({
      label: idx === 0
        ? `Highest: YE Oct ${r.yearEndingOctober} (${r.total.toFixed(1)}mm)`
        : `High year: YE Oct ${r.yearEndingOctober}`,
      data: r.points,
      borderColor: COLOURS.high,
      borderWidth: widths[idx],
      pointRadius: 0,
      tension: 0,
      order: 6 + idx
    });
  });

  bottom3.forEach((r, idx) => {
    datasets.push({
      label: idx === 0
        ? `Lowest: YE Oct ${r.yearEndingOctober} (${r.total.toFixed(1)}mm)`
        : `Low year: YE Oct ${r.yearEndingOctober}`,
      data: r.points,
      borderColor: COLOURS.low,
      borderWidth: widths[idx],
      pointRadius: 0,
      tension: 0,
      order: 6 + idx
    });
  });

  const medianSeries = buildMedianSeries(records);
  datasets.push({
    label: `Median (${medianSeries[11].y.toFixed(1)}mm)`,
    data: medianSeries,
    borderColor: COLOURS.median,
    borderWidth: 3,
    pointRadius: 0,
    borderDash: [6, 4],
    tension: 0,
    order: 4
  });

  if (currentDaily && currentDaily.length) {
    const last = latestDailyPoint(currentDaily);
    datasets.push({
      label: `YE Oct 2026 (${round1(last.cumulative_mm).toFixed(1)}mm to ${formatDate(last.date)})`,
      data: currentDaily.map(d => ({ x: Number(d.x), y: Number(d.cumulative_mm) })),
      borderColor: COLOURS.current,
      borderWidth: 3.8,
      pointRadius: 0,
      tension: 0,
      order: 1
    });
  }

  return { datasets, top3, bottom3, medianSeries };
}

function monthTickLabel(value) {
  const idx = Math.round(value);
  return MONTHS_RAINFALL_YEAR[idx] || "";
}

function formatDate(iso) {
  const d = new Date(`${iso}T00:00:00`);
  return d.toLocaleDateString("en-AU", { day: "2-digit", month: "short", year: "numeric" });
}

const endpointLabelsPlugin = {
  id: "endpointLabels",
  afterDatasetsDraw(chart, args, opts) {
    const { ctx, chartArea, scales } = chart;
    if (!opts) return;

    const xScale = scales.x;
    const yScale = scales.y;
    const labelX = xScale.getPixelForValue(11) + 20;

    ctx.save();
    ctx.textAlign = "left";
    ctx.textBaseline = "middle";

    function drawLabel(text, y, colour, bold = false) {
      ctx.font = `${bold ? "700" : "500"} 12px -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif`;
      ctx.fillStyle = colour;
      text.split("\n").forEach((line, i, arr) => {
        ctx.fillText(line, labelX, y + (i - (arr.length - 1) / 2) * 14);
      });
    }

    opts.top3.forEach((r, idx) => {
      const yPositions = [yScale.getPixelForValue(426), yScale.getPixelForValue(397), yScale.getPixelForValue(357)];
      const text = idx === 0 ? `${r.yearEndingOctober}\n${r.total.toFixed(1)}mm` : `${r.yearEndingOctober}`;
      drawLabel(text, yPositions[idx], COLOURS.high, idx === 0);
    });

    opts.bottom3.forEach((r, idx) => {
      const yPositions = [yScale.getPixelForValue(132), yScale.getPixelForValue(190), yScale.getPixelForValue(216)];
      const text = idx === 0 ? `${r.yearEndingOctober}\n${r.total.toFixed(1)}mm` : `${r.yearEndingOctober}`;
      drawLabel(text, yPositions[idx], COLOURS.low, idx === 0);
    });

    if (opts.medianSeries) {
      const med = opts.medianSeries[opts.medianSeries.length - 1].y;
      drawLabel(`Median\n${med.toFixed(1)}mm`, yScale.getPixelForValue(med), COLOURS.median, true);
    }

    if (opts.currentDaily && opts.currentDaily.length) {
      const last = opts.currentDaily[opts.currentDaily.length - 1];
      drawLabel(`2026\n${round1(last.cumulative_mm).toFixed(1)}mm`, yScale.getPixelForValue(last.cumulative_mm) - 8, COLOURS.current, true);
    }

    ctx.restore();
  }
};

Chart.register(endpointLabelsPlugin);

async function loadCurrentYear() {
  const response = await fetch(`data/current-year.json?ts=${Date.now()}`, { cache: "no-store" });
  if (!response.ok) throw new Error(`Could not load current-year.json: ${response.status}`);
  return response.json();
}

function renderSummary(records, currentDaily, top3, bottom3, medianSeries, updatedAt) {
  const last = currentDaily?.length ? latestDailyPoint(currentDaily) : null;
  const summary = document.getElementById("summary");
  summary.innerHTML = "";

  const cards = [
    ["Current", last ? `${round1(last.cumulative_mm).toFixed(1)}mm` : "n/a", last ? `to ${formatDate(last.date)}` : ""],
    ["Highest", `${top3[0].total.toFixed(1)}mm`, `YE Oct ${top3[0].yearEndingOctober}`],
    ["Lowest", `${bottom3[0].total.toFixed(1)}mm`, `YE Oct ${bottom3[0].yearEndingOctober}`],
    ["Median", `${medianSeries[11].y.toFixed(1)}mm`, "YE Oct cumulative"]
  ];

  cards.forEach(([label, value, sub]) => {
    const card = document.createElement("div");
    card.className = "summary-card";
    card.innerHTML = `<div class="label">${label}</div><div class="value">${value}</div><div class="sub">${sub}</div>`;
    summary.appendChild(card);
  });

  const status = document.getElementById("status");
  const updated = updatedAt ? new Date(updatedAt).toLocaleString("en-AU", { dateStyle: "medium", timeStyle: "short" }) : "unknown";
  status.textContent = `Data refreshed: ${updated}`;
}

async function main() {
  const records = buildHistoricalRainfallYears();
  const current = await loadCurrentYear();
  const currentDaily = current.daily || [];
  const { datasets, top3, bottom3, medianSeries } = buildDatasets(records, currentDaily);

  const ctx = document.getElementById("rainfallChart");

  new Chart(ctx, {
    type: "line",
    data: { datasets },
    options: {
      animation: false,
      maintainAspectRatio: false,
      parsing: false,
      normalized: true,
      interaction: {
        mode: "nearest",
        intersect: false
      },
      layout: {
        padding: {
          top: 8,
          right: 118,
          left: 6,
          bottom: 0
        }
      },
      plugins: {
        legend: {
          position: "top",
          align: "center",
          onClick: null,
          labels: {
            boxWidth: 34,
            usePointStyle: false,
            font: { size: window.innerHeight < 520 ? 10 : 12 },
            generateLabels: chart => [
              {
                text: "Current rainfall year",
                fillStyle: COLOURS.current,
                strokeStyle: COLOURS.current,
                lineWidth: 4,
                hidden: false,
                datasetIndex: -1
              },
              {
                text: "3 wettest years",
                fillStyle: COLOURS.high,
                strokeStyle: COLOURS.high,
                lineWidth: 4,
                hidden: false,
                datasetIndex: -1
              },
              {
                text: "3 driest years",
                fillStyle: COLOURS.low,
                strokeStyle: COLOURS.low,
                lineWidth: 4,
                hidden: false,
                datasetIndex: -1
              }
            ]
          }
        },
        tooltip: {
          callbacks: {
            label: ctx => `${ctx.dataset.label}: ${round1(ctx.parsed.y).toFixed(1)}mm`
          }
        },
        endpointLabels: {
          top3,
          bottom3,
          medianSeries,
          currentDaily
        }
      },
      scales: {
        x: {
          type: "linear",
          min: 0,
          max: 12.45,
          grid: { display: false },
          border: { color: "#CFCFCF" },
          ticks: {
            stepSize: 1,
            callback: monthTickLabel,
            color: "#333333"
          }
        },
        y: {
          min: 0,
          max: 465,
          grid: { display: false },
          border: { color: "#CFCFCF" },
          title: {
            display: true,
            text: "Cumulative rainfall (mm)"
          },
          ticks: {
            color: "#333333"
          }
        }
      }
    }
  });

  renderSummary(records, currentDaily, top3, bottom3, medianSeries, current.updatedAt);
}

main().catch(err => {
  console.error(err);
  document.getElementById("status").textContent = `Error: ${err.message}`;
});
